#include <bits/stdc++.h>
using namespace std;

struct Fence {
    long long x, y;
    int dir; // 0 for '/', 1 for '\'
};

// Reflects direction after hitting a '/' fence
// Incoming direction dir: 0=right, 1=up, 2=left, 3=down
// '/' reflects: right->up, up->right, left->down, down->left
int reflect_slash(int in_dir) {
    // '/' mirror: (right,up)->(up,right), (left,down)->(down,left)
    // In terms of our encoding:
    // 0(right) -> 1(up)
    // 1(up) -> 0(right)
    // 2(left) -> 3(down)
    // 3(down) -> 2(left)
    if (in_dir == 0) return 1;
    if (in_dir == 1) return 0;
    if (in_dir == 2) return 3;
    return 2; // in_dir == 3
}

// '\' reflects: right->down, down->right, left->up, up->left
int reflect_backslash(int in_dir) {
    // 0(right) -> 3(down)
    // 1(up) -> 2(left)
    // 2(left) -> 1(up)
    // 3(down) -> 0(right)
    if (in_dir == 0) return 3;
    if (in_dir == 1) return 2;
    if (in_dir == 2) return 1;
    return 0;
}

// Check if starting from (0,0) going right (+x), we hit (a,b) with given fence configurations
// We need to find the FIRST fence whose toggling makes it possible.
// Since N <= 200, we can try all possibilities + the original.

// Helper: check if we can reach (a,b) from (0,0) going right with given fence config
// The ray moves along lines at 45 degrees. Actually, the ray always moves axis-aligned
// because mirrors are at 45 degrees. Let's think carefully.
//
// Starting from (0,0) going right. After hitting a '/' mirror, ray goes up.
// After hitting a '\' mirror, ray goes down.
// After hitting a '/' going up, ray goes right.
// etc.
//
// So the ray always moves in one of 4 axis-aligned directions.
// The ray travels along a grid line. When it hits a fence at (x_i, y_i), 
// the fence acts like a 45-degree mirror.
//
// A '/' fence centered at (x,y): it's a line segment from (x-0.1, y-0.1) to (x+0.1, y+0.1)
// tilted like /. So it reflects: incoming from left (going right) -> goes up,
// incoming from right (going left) -> goes down, incoming from below (going up) -> goes right,
// incoming from above (going down) -> goes left.
// That matches our reflect_slash.
//
// A '\' fence centered at (x,y): segment from (x-0.1, y+0.1) to (x+0.1, y-0.1)
// reflects: right->down, down->right, left->up, up->left.
// That matches reflect_backslash.
//
// Now, the ray starts at (0,0) going right. It will travel along the line y=0.
// It will hit a fence at (x_i, y_i) only if y_i == 0 and x_i > 0... but wait,
// fences are at integer coordinates and the ray travels exactly on integer grid lines?
// Actually the ray from (0,0) going right stays on y=0. So it would only hit fences with y_i=0 and x_i>0.
// But then after reflection going up, it goes along x = x_i, upwards.
// Then it could hit fences with x_j == x_i and y_j > y_i.
// That seems too restrictive. Let's re-read the problem...
//
// "a short line segment centered at integer location (x_i, y_i)"
// "For example, a fence oriented like '/' at position (3,5) could be described as a line segment from (2.9,4.9) to (3.1,5.1)."
//
// The segment is very short (length ~0.2828). So the ray must pass through the exact center (x_i,y_i) to hit it.
// But wait, the ray could hit the fence at some offset. Since the fence is very short, the ray must 
// come very close to the center.
//
// Actually, the classical "mirror" problem (like USACO "mirror" or similar) works like this:
// The ray moves along grid lines at 45 degrees. The mirrors are placed at integer coordinates.
// When the ray hits (x_i, y_i), it reflects based on the mirror type.
// The ray starts at (0,0) going towards +x direction, i.e., along the diagonal? 
// No, it says "look directly to the right (in the +x direction)".
//
// Hmm, let me reconsider. Maybe the ray isn't constrained to grid lines. Let me think about
// this more carefully.
//
// Actually, looking at the example would help. But the example isn't given fully.
// Let me re-read the scraped text:
// "With his gaze bouncing off some of the reflective fences on his farm"
//
// The key insight: The fences are 45-degree line segments. The ray of light travels 
// along paths that reflect off these segments.
//
// For a '/' mirror at (x,y), the line is from (x-0.1,y-0.1) to (x+0.1,y+0.1).
// This means the line equation is y = x + (y_i - x_i). Actually more precisely, 
// it's along the line with slope 1.
//
// For a '\' mirror at (x,y), the line is from (x-0.1,y+0.1) to (x+0.1,y-0.1).
// This means the line equation is y = -x + (y_i + x_i). Slope -1.
//
// The ray starts at (0,0) going right (direction vector (1,0)).
// When it hits a '/' mirror, it reflects. The mirror is at 45 degrees.
// The reflection law: angle of incidence = angle of reflection.
// For '/' (slope 1, angle 45° with x-axis), incoming horizontal ray hits:
// normal of '/' is at 135° (or -45°). Actually mirror '/' has normal at 135° from +x.
// A horizontal ray coming from left hits '/' and reflects upward (vertical).
// So incoming (1,0) reflects to (0,1). That matches.
//
// For '\' (slope -1, angle 135° or -45°), normal is at 45°.
// Incoming horizontal ray from left hits '\' and reflects downward (0,-1). 
// So incoming (1,0) reflects to (0,-1).
//
// Now, after going upward from a '/' at (x,y), the ray travels along x = x, going upward.
// It will next hit a mirror if there's a mirror at (x_i, y_i) such that x_i == x (same x-coordinate)
// and y_i > y, and the ray going upward reaches it.
//
// But wait - what about hitting the next mirror that is NOT aligned?
// The ray is always moving either horizontally or vertically (axis-aligned).
// Because mirrors are at 45°, they always swap horizontal/vertical directions.
// So the ray is always axis-aligned.
//
// Let's verify: starting right -> hit '/' -> go up -> hit '/' -> go right -> ...
// Starting right -> hit '\' -> go down -> hit '\' -> go right -> ...
// Starting right -> hit '/' -> go up -> hit '\' -> go left -> ...
// etc.
//
// So the path consists of horizontal and vertical segments.
// The ray only changes direction at a mirror.
//
// To hit a mirror at (x_i, y_i):
// - If coming from left (going right), we need the ray's y-coordinate to be y_i 
//   and its x-coordinate to be < x_i (just before hitting), and no other mirror at same y between.
// - If coming from right (going left), we need y == y_i and x > x_i.
// - If coming from below (going up), we need x == x_i and y < y_i.
// - If coming from above (going down), we need x == x_i and y > y_i.
//
// This is a classic simulation problem. We simulate the ray step by step.
// At each step, we're at some position (px, py) going in direction dir.
// We need to find the next mirror we hit.
//
// For a given direction:
// dir=0 (right): look for mirrors with y==py and x>px. Pick the one with smallest x>px.
// dir=1 (up): look for mirrors with x==px and y>py. Pick the one with smallest y>py.
// dir=2 (left): look for mirrors with y==py and x<px. Pick the one with largest x<px.
// dir=3 (down): look for mirrors with x==px and y<py. Pick the one with largest y<py.
//
// If no mirror found in that direction, the ray goes to infinity and won't reach (a,b).
//
// But wait, the ray also needs to potentially hit (a,b)! The ray is a continuous path.
// It passes through (a,b) if at some point, the ray's path contains the point (a,b).
// Since the ray is axis-aligned, this means:
// - If going right: (a,b) is on the ray if py == b and a >= px (and a reaches before any mirror further right)
// - If going up: (a,b) is on the ray if px == a and b >= py
// - If going left: (a,b) is on the ray if py == b and a <= px
// - If going down: (a,b) is on the ray if px == a and b <= py
//
// And also (a,b) must be reachable before hitting the next mirror.
// So when checking if (a,b) is reachable, we need to see if the ray passes through (a,b)
// before hitting any mirror.
//
// Let's implement this.

bool canSee(long long a, long long b, const vector<Fence>& fences) {
    long long px = 0, py = 0;
    int dir = 0; // start going right

    // To avoid infinite loops, track visited (x,y,dir) states.
    // Since N <= 200 and coordinates are large, but number of states is bounded.
    // Actually, the ray can cycle. So we need cycle detection.
    set<tuple<long long, long long, int>> visited;

    while (true) {
        // Check if (a,b) is on the current ray before the next mirror
        if (dir == 0) { // going right
            if (py == b && px <= a) {
                // Check if any mirror blocks the view to (a,b)
                // i.e., is there a mirror at (x,y) with y==b and px < x < a?
                bool blocked = false;
                for (const auto& f : fences) {
                    if (f.y == b && f.x > px && f.x < a) {
                        blocked = true;
                        break;
                    }
                }
                if (!blocked) return true;
            }
        } else if (dir == 1) { // going up
            if (px == a && py <= b) {
                bool blocked = false;
                for (const auto& f : fences) {
                    if (f.x == a && f.y > py && f.y < b) {
                        blocked = true;
                        break;
                    }
                }
                if (!blocked) return true;
            }
        } else if (dir == 2) { // going left
            if (py == b && px >= a) {
                bool blocked = false;
                for (const auto& f : fences) {
                    if (f.y == b && f.x < px && f.x > a) {
                        blocked = true;
                        break;
                    }
                }
                if (!blocked) return true;
            }
        } else { // going down
            if (px == a && py >= b) {
                bool blocked = false;
                for (const auto& f : fences) {
                    if (f.x == a && f.y < py && f.y > b) {
                        blocked = true;
                        break;
                    }
                }
                if (!blocked) return true;
            }
        }

        // Find next fence
        long long next_x = -1, next_y = -1;
        int next_dir = -1;
        if (dir == 0) { // right
            long long best_x = LLONG_MAX;
            for (const auto& f : fences) {
                if (f.y == py && f.x > px && f.x < best_x) {
                    best_x = f.x;
                    next_x = f.x;
                    next_y = f.y;
                    next_dir = (f.dir == 0) ? reflect_slash(dir) : reflect_backslash(dir);
                }
            }
        } else if (dir == 1) { // up
            long long best_y = LLONG_MAX;
            for (const auto& f : fences) {
                if (f.x == px && f.y > py && f.y < best_y) {
                    best_y = f.y;
                    next_x = f.x;
                    next_y = f.y;
                    next_dir = (f.dir == 0) ? reflect_slash(dir) : reflect_backslash(dir);
                }
            }
        } else if (dir == 2) { // left
            long long best_x = LLONG_MIN;
            for (const auto& f : fences) {
                if (f.y == py && f.x < px && f.x > best_x) {
                    best_x = f.x;
                    next_x = f.x;
                    next_y = f.y;
                    next_dir = (f.dir == 0) ? reflect_slash(dir) : reflect_backslash(dir);
                }
            }
        } else { // down
            long long best_y = LLONG_MIN;
            for (const auto& f : fences) {
                if (f.x == px && f.y < py && f.y > best_y) {
                    best_y = f.y;
                    next_x = f.x;
                    next_y = f.y;
                    next_dir = (f.dir == 0) ? reflect_slash(dir) : reflect_backslash(dir);
                }
            }
        }

        if (next_x == -1) {
            // No more mirrors, ray goes to infinity
            return false;
        }

        // Move to the mirror
        px = next_x;
        py = next_y;
        dir = next_dir;

        // Cycle detection
        auto state = make_tuple(px, py, dir);
        if (visited.count(state)) return false;
        visited.insert(state);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    long long a, b;
    cin >> N >> a >> b;

    vector<Fence> fences(N);
    for (int i = 0; i < N; i++) {
        long long x, y;
        char d;
        cin >> x >> y >> d;
        fences[i].x = x;
        fences[i].y = y;
        fences[i].dir = (d == '/') ? 0 : 1;
    }

    // Check without toggling any fence
    if (canSee(a, b, fences)) {
        cout << 0 << "\n";
        return 0;
    }

    // Try toggling each fence
    for (int i = 0; i < N; i++) {
        // Toggle
        fences[i].dir ^= 1;
        if (canSee(a, b, fences)) {
            cout << (i + 1) << "\n";
            return 0;
        }
        // Toggle back
        fences[i].dir ^= 1;
    }

    cout << -1 << "\n";
    return 0;
}
